import React, { useState, useEffect } from 'react';
import './Header.css';

const DESTINATIONS = [
  'SFO → JFK', 'LAX → ORD', 'ATL → MIA', 'DFW → SEA',
  'BOS → DEN', 'LAS → PHX', 'MSP → DTW', 'CLT → PHL',
];

export default function Header({ onClearChat, onSettings }) {
  const [destIdx, setDestIdx]   = useState(0);
  const [flipping, setFlipping] = useState(false);
  const [clock, setClock]       = useState('');

  // Flip-board destination cycle
  useEffect(() => {
    const id = setInterval(() => {
      setFlipping(true);
      setTimeout(() => {
        setDestIdx(i => (i + 1) % DESTINATIONS.length);
        setFlipping(false);
      }, 250);
    }, 3000);
    return () => clearInterval(id);
  }, []);

  // Live clock
  useEffect(() => {
    const tick = () => setClock(new Date().toLocaleTimeString('en-US', { hour12: false }));
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, []);

  return (
    <header className="app-header">
      <div className="header-left">
        <div className="logo-block">
          <span className="logo-icon">✈</span>
          <div className="logo-text">
            <span className="logo-title">FLIGHTIQ</span>
            <span className="logo-sub">Data Intelligence Terminal</span>
          </div>
        </div>

        <div className="board-display">
          <span className="board-label">NOW SERVING</span>
          <span className={`board-dest ${flipping ? 'flipping' : ''}`}>
            {DESTINATIONS[destIdx]}
          </span>
        </div>
      </div>

      <div className="header-right">
        <div className="status-cluster">
          <div className="status-dot active" />
          <span className="status-text">BACKEND LIVE</span>
        </div>
        <div className="clock">{clock}</div>
        <button className="header-btn" onClick={onSettings} title="Settings">
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <circle cx="12" cy="12" r="3"/>
            <path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/>
          </svg>
        </button>
        <button className="header-btn danger" onClick={onClearChat} title="Clear chat">
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14H6L5 6"/><path d="M10 11v6M14 11v6"/>
            <path d="M9 6V4h6v2"/>
          </svg>
        </button>
      </div>
    </header>
  );
}
